useEffect(() => {
  viewingSeconds = 0;
  setViewingTime(0);
  const id = setInterval(() => {
    viewingSeconds += 1;
    setViewingTime(viewingSeconds);
  }, 1000);
  return () => clearInterval(id);
}, []);

